+function scenarioEnv(options: OpenClawTestStateOptions): Record<string, string | undefined> {
+  if ((options.scenario ?? "empty") === "external-service") {
+    return {
+      OPENCLAW_SERVICE_REPAIR_POLICY: "external",
+    };
+  }
+  return {};
